# AUTH MIDDLEWARE FOR PORTABLEDADANSWERS

## 1. ACTUAL CODE

### A. Auth Middleware (Node.js/Express)

```javascript
// portabledadanswers/middleware/auth.js
const axios = require('axios');

class AuthMiddleware {
  constructor(angelCloudUrl = 'http://localhost:5000') {
    this.angelCloudUrl = angelCloudUrl;
  }

  // Main middleware function
  validateToken() {
    return async (req, res, next) => {
      try {
        // Extract token from header
        const authHeader = req.headers.authorization;
        if (!authHeader || !authHeader.startsWith('Bearer ')) {
          return res.status(401).json({ 
            error: 'No token provided',
            message: 'Authorization header must be: Bearer <token>'
          });
        }

        const token = authHeader.substring(7);

        // Validate with angelcloud-actual
        const validationResponse = await axios.post(
          `${this.angelCloudUrl}/auth`,
          {},
          {
            headers: {
              'Authorization': `Bearer ${token}`,
              'Content-Type': 'application/json'
            }
          }
        );

        if (validationResponse.status === 200) {
          // Token is valid - attach user info to request
          req.user = validationResponse.data.user || { token: token };
          next();
        } else {
          return res.status(401).json({ 
            error: 'Invalid token',
            message: 'Token validation failed'
          });
        }

      } catch (error) {
        console.error('Auth validation error:', error.message);
        return res.status(401).json({ 
          error: 'Authentication failed',
          message: error.response?.data?.error || 'Could not validate token'
        });
      }
    };
  }

  // Optional: Check specific permissions
  requirePermission(permission) {
    return (req, res, next) => {
      if (!req.user) {
        return res.status(401).json({ error: 'Not authenticated' });
      }

      // Add permission logic here if needed
      if (req.user.permissions && !req.user.permissions.includes(permission)) {
        return res.status(403).json({ error: 'Insufficient permissions' });
      }

      next();
    };
  }
}

module.exports = AuthMiddleware;
```

