# LogiBot Automation Engine - READY TO DEPLOY

## 1. CORE ENGINE CODE

Create `logibot-core/automation-engine.js`:

```javascript
const EventEmitter = require('events');
const fs = require('fs').promises;
const path = require('path');

class LogiBot extends EventEmitter {
  constructor(config = {}) {
    super();
    this.config = {
      rulesPath: config.rulesPath || './automation-rules',
      logPath: config.logPath || './logs',
      maxConcurrentTasks: config.maxConcurrentTasks || 10,
      ...config
    };
    this.activeRules = new Map();
    this.taskQueue = [];
    this.runningTasks = new Set();
    this.initialized = false;
  }

  async initialize() {
    try {
      // Ensure directories exist
      await this.ensureDirectories();

      // Load automation rules
      await this.loadRules();

      // Start monitoring
      this.startMonitoring();

      this.initialized = true;
      this.log('LogiBot initialized successfully');
      return true;
    } catch (error) {
      this.log('Failed to initialize LogiBot: ' + error.message);
      throw error;
    }
  }

  // BASIC AUTOMATION FUNCTIONS

  async automate(taskName, data = {}) {
    if (!this.initialized) {
      throw new Error('LogiBot not initialized. Call initialize() first.');
    }

    const task = {
      id: this.generateTaskId(),
      name: taskName,
      data,
      createdAt: new Date(),
      status: 'pending'
    };

    this.taskQueue.push(task);
    this.processQueue();

    return task.id;
  }

  async createRule(ruleName, condition, action) {
    const rule = {
      name: ruleName,
      condition: condition, // Function that returns boolean
      action: action,       // Function to execute
      enabled: true,
      createdAt: new Date(),
      lastTriggered: null,
      triggerCount: 0
    };

    this.activeRules.set(ruleName, rule);
    await this.saveRule(rule);

    this.log(`Rule created: ${ruleName}`);
    return rule;
  }

  async scheduleTask(cronExpression, taskName, data = {}) {
    // Simple scheduler - runs every minute and checks conditions
    const scheduledTask = {
      cron: cronExpression,
      taskName,
      data,
      nextRun: this.calculateNextRun(cronExpression),
      enabled: true
    };

    // Store in rules as a special type
    await this.createRule(`scheduled_${taskName}`, 
      () => this.shouldRunScheduledTask(scheduledTask),
      () => this.automate(taskName, data)
    );

    return scheduledTask;
  }

  // EMAIL AUTOMATION
  async automateEmail(trigger, emailConfig) {
    const emailRule = await this.createRule(
      `email_${trigger}`,
      (data) => data.trigger === trigger,
      async (data) => {
        await this.sendEmail({
          to: data.email || emailConfig.defaultTo,
          subject: this.processTemplate(emailConfig.subject, data),
          body: this.processTemplate(emailConfig.body, data)
        });
      }
    );

    return emailRule;
  }

  // FILE AUTOMATION
  async automateFileProcessing(watchPath, processor) {
    const rule = await this.createRule(
      `file_watcher_${Date.now()}`,
      (data) => data.type === 'file_change' && data.path.includes(watchPath),
      async (data) => {
        await processor(data.path, data.content);
      }
    );

    // Start watching the directory
    this.watchDirectory(watchPath);
    return rule;
  }

  // WEBHOOK AUTOMATION
  async automateWebhook(webhook, processor) {
    const rule = await this.createRule(
      `webhook_${webhook}`,
      (data) => data.type === 'webhook' && data.webhook === webhook,
      processor
    );

    return rule;
  }

  // PRIVATE METHODS

  async processQueue() {
    if (this.runningTasks.size >= this.config.maxConcurrentTasks) {
      return;
    }

    const task = this.taskQueue.shift();
    if (!task) return;

    this.runningTasks.add(task.id);
    task.status = 'running';
    task.startedAt = new Date();

    try {
      await this.executeTask(task);
      task.status = 'completed';
      task.completedAt = new Date();
      this.log(`Task completed: ${task.name}`);
    } catch (error) {
      task.status = 'failed';
      task.error = error.message;
      task.failedAt = new Date();
      this.log(`Task failed: ${task.name} - ${error.message}`);
    } finally {
      this.runningTasks.delete(task.id);
      this.emit('taskComplete', task);

      // Process next task
      if (this.taskQueue.length > 0) {
        setTimeout(() => this.processQueue(), 100);
      }
    }
  }

  async executeTask(task) {
    // Check if any rules should handle this task
    for (const [ruleName, rule] of this.activeRules) {
      if (rule.enabled && rule.condition(task.data)) {
        rule.lastTriggered = new Date();
        rule.triggerCount++;
        await rule.action(task.data);
        this.log(`Rule triggered: ${ruleName}`);
      }
    }
  }

  startMonitoring() {
    // Check rules every 30 seconds
    setInterval(() => {
      this.checkAllRules();
    }, 30000);
  }

  async checkAllRules() {
    const currentData = {
      timestamp: new Date(),
      type: 'scheduled_check'
    };

    for (const [ruleName, rule] of this.activeRules) {
      if (rule.enabled) {
        try {
          if (rule.condition(currentData)) {
            await this.automate('rule_triggered', { ruleName, ...currentData });
          }
        } catch (error) {
          this.log(`Rule check failed: ${ruleName} - ${error.message}`);
        }
      }
    }
  }

  generateTaskId() {
    return 'task_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
  }

  async ensureDirectories() {
    const dirs = [this.config.rulesPath, this.config.logPath];
    for (const dir of dirs) {
      try {
        await fs.access(dir);
      } catch {
        await fs.mkdir(dir, { recursive: true });
      }
    }
  }

  async loadRules() {
    try {
      const rulesFile = path.join(this.config.rulesPath, 'active-rules.json');
      const rulesData = await fs.readFile(rulesFile, 'utf8');
      const rules = JSON.parse(rulesData);

      // Note: Functions can't be serialized, so rules loaded this way need to be re-initialized
      this.log(`Loaded ${rules.length} rules from storage`);
    } catch (error) {
      this.log('No existing rules found, starting fresh');
    }
  }

  async saveRule(rule) {
    const rulesFile = path.join(this.config.rulesPath, `${rule.name}.json`);
    const serializable = {
      name: rule.name,
      enabled: rule.enabled,
      createdAt: rule.createdAt,
      lastTriggered: rule.lastTriggered,
      triggerCount: rule.triggerCount
    };
    await fs.writeFile(rulesFile, JSON.stringify(serializable, null, 2));
  }

  processTemplate(template, data) {
    return template.replace(/\{\{(\w+)\}\}/g, (match, key) => {
      return data[key] || match;
    });
  }

  async sendEmail(config) {
    // Integration point with angelcloud-actual email system
    this.log(`Email sent: ${config.subject} to ${config.to}`);
    this.emit('emailSent', config);
  }

  watchDirectory(dirPath) {
    // File system watcher - simplified for now
    this.log(`Watching directory: ${dirPath}`);
  }

  calculateNextRun(cronExpression) {
    // Simplified cron - just return next minute for now
    const next = new Date();
    next.setMinutes(next.getMinutes() + 1);
    return next;
  }

  shouldRunScheduledTask(task) {
    return task.enabled && new Date() >= task.nextRun;
  }

  log(message) {
    const logEntry = `[${new Date().toISOString()}] ${message}`;
    console.log(logEntry);
    this.emit('log', logEntry);
  }

  // PUBLIC API FOR STATUS
  getStatus() {
    return {
      initialized: this.initialized,
      activeRules: this.activeRules.size,
      queuedTasks: this.taskQueue.length,
      runningTasks: this.runningTasks.size
    };
  }

  getRules() {
    return Array.from(this.activeRules.values());
  }

  getTaskQueue() {
    return [...this.taskQueue];
  }
}

module.exports = LogiBot;
```

