```javascript
// memory-pipeline/memory-pipeline.js
const fs = require('fs').promises;
const path = require('path');
const chokidar = require('chokidar');

class MemoryPipeline {
  constructor() {
    this.dailyMemoryPath = '../daily-memory-updated';
    this.shaneBrainPath = '../shanebrain-core';
    this.processedMemories = new Set();
  }

  async start() {
    console.log('🧠 Memory Pipeline starting...');

    // Process existing memories first
    await this.processExistingMemories();

    // Watch for new memories
    this.watchForNewMemories();

    console.log('✅ Memory Pipeline active - watching for memories');
  }

  async processExistingMemories() {
    try {
      const memoryFiles = await this.findMemoryFiles();
      console.log(`📁 Found ${memoryFiles.length} existing memory files`);

      for (const file of memoryFiles) {
        await this.ingestMemory(file);
      }
    } catch (error) {
      console.error('❌ Error processing existing memories:', error);
    }
  }

  async findMemoryFiles() {
    const files = [];
    const searchPaths = [
      path.join(this.dailyMemoryPath, 'memories'),
      path.join(this.dailyMemoryPath, 'entries'),
      path.join(this.dailyMemoryPath, 'src'),
      this.dailyMemoryPath
    ];

    for (const searchPath of searchPaths) {
      try {
        const dirFiles = await fs.readdir(searchPath, { withFileTypes: true });
        for (const file of dirFiles) {
          if (file.isFile() && (file.name.endsWith('.md') || file.name.endsWith('.txt'))) {
            files.push(path.join(searchPath, file.name));
          }
        }
      } catch (error) {
        // Directory might not exist, skip silently
      }
    }

    return files;
  }

  watchForNewMemories() {
    const watcher = chokidar.watch([
      `${this.dailyMemoryPath}/**/*.md`,
      `${this.dailyMemoryPath}/**/*.txt`,
      `${this.dailyMemoryPath}/**/*.json`
    ]);

    watcher.on('add', (filePath) => {
      console.log(`📝 New memory detected: ${path.basename(filePath)}`);
      this.ingestMemory(filePath);
    });

    watcher.on('change', (filePath) => {
      console.log(`✏️  Memory updated: ${path.basename(filePath)}`);
      this.ingestMemory(filePath);
    });
  }

  async ingestMemory(filePath) {
    try {
      const content = await fs.readFile(filePath, 'utf8');
      const fileName = path.basename(filePath);

      if (this.processedMemories.has(filePath)) {
        console.log(`⏭️  Skipping already processed: ${fileName}`);
        return;
      }

      const processedMemory = this.processMemoryContent(content, fileName);
      await this.saveToShaneBrain(processedMemory);

      this.processedMemories.add(filePath);
      console.log(`✅ Ingested memory: ${fileName}`);
    } catch (error) {
      console.error(`❌ Failed to ingest ${filePath}:`, error.message);
    }
  }

  processMemoryContent(content, fileName) {
    const timestamp = new Date().toISOString();
    const date = fileName.match(/\d{4}-\d{2}-\d{2}/) || [timestamp.split('T')[0]];

    return {
      id: `memory_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      timestamp,
      date: date[0],
      source: 'daily-memory',
      fileName,
      content: content.trim(),
      processed: timestamp,
      type: this.detectMemoryType(content),
      keywords: this.extractKeywords(content)
    };
  }

  detectMemoryType(content) {
    const lower = content.toLowerCase();
    if (lower.includes('project') || lower.includes('code') || lower.includes('build')) return 'project';
    if (lower.includes('meeting') || lower.includes('call') || lower.includes('client')) return 'business';
    if (lower.includes('idea') || lower.includes('thought') || lower.includes('concept')) return 'idea';
    if (lower.includes('family') || lower.includes('personal')) return 'personal';
    return 'general';
  }

  extractKeywords(content) {
    const words = content.toLowerCase()
      .replace(/[^\w\s]/g, ' ')
      .split(/\s+/)
      .filter(word => word.length > 3)
      .filter(word => !['that', 'this', 'with', 'have', 'will', 'been', 'from', 'they', 'were', 'said'].includes(word));

    return [...new Set(words)].slice(0, 10);
  }

  async saveToShaneBrain(memory) {
    const brainDir = path.join(this.shaneBrainPath, 'memories');
    const indexFile = path.join(this.shaneBrainPath, 'memory-index.json');

    // Create directories if they don't exist
    await fs.mkdir(brainDir, { recursive: true });

    // Save individual memory file
    const memoryFile = path.join(brainDir, `${memory.id}.json`);
    await fs.writeFile(memoryFile, JSON.stringify(memory, null, 2));

    // Update memory index
    await this.updateMemoryIndex(memory, indexFile);
  }

  async updateMemoryIndex(memory, indexFile) {
    let index = { memories: [], lastUpdated: null, totalCount: 0 };

    try {
      const existingIndex = await fs.readFile(indexFile, 'utf8');
      index = JSON.parse(existingIndex);
    } catch (error) {
      // Index doesn't exist yet, use default
    }

    // Remove existing entry if updating
    index.memories = index.memories.filter(m => m.id !== memory.id);

    // Add new/updated memory
    index.memories.unshift({
      id: memory.id,
      date: memory.date,
      type: memory.type,
      fileName: memory.fileName,
      keywords: memory.keywords,
      processed: memory.processed
    });

    // Keep only last 1000 entries in index
    index.memories = index.memories.slice(0, 1000);
    index.lastUpdated = new Date().toISOString();
    index.totalCount = index.memories.length;

    await fs.writeFile(indexFile, JSON.stringify(index, null, 2));
  }
}

module.exports = MemoryPipeline;
```

### B. ShaneBrain Memory Reader (`shanebrain-memory-reader.js`)
```javascript
// shanebrain-core/memory-reader.js
const fs = require('fs').promises;
const path = require('path');

class ShaneBrainMemoryReader {
  constructor() {
    this.memoriesPath = path.join(__dirname, 'memories');
    this.indexPath = path.join(__dirname, 'memory-index.json');
  }

  async getRecentMemories(days = 7) {
    try {
      const index = await this.loadIndex();
      const cutoffDate = new Date();
      cutoffDate.setDate(cutoffDate.getDate() - days);

      return index.memories.filter(memory => {
        const memoryDate = new Date(memory.date);
        return memoryDate >= cutoffDate;
      });
    } catch (error) {
      console.error('Error loading recent memories:', error);
      return [];
    }
  }

  async searchMemories(query, limit = 10) {
    try {
      const index = await this.loadIndex();
      const queryWords = query.toLowerCase().split(/\s+/);

      const scored = index.memories.map(memory => {
        let score = 0;
        queryWords.forEach(word => {
          if (memory.keywords.some(keyword => keyword.includes(word))) {
            score += 2;
          }
          if (memory.fileName.toLowerCase().includes(word)) {
            score += 1;
          }
        });
        return { ...memory, score };
      });

      return scored
        .filter(memory => memory.score > 0)
        .sort((a, b) => b.score - a.score)
        .slice(0, limit);
    } catch (error) {
      console.error('Error searching memories:', error);
      return [];
    }
  }

  async getMemoryContent(memoryId) {
    try {
      const memoryFile = path.join(this.memoriesPath, `${memoryId}.json`);
      const content = await fs.readFile(memoryFile, 'utf8');
      return JSON.parse(content);
    } catch (error) {
      console.error(`Error loading memory ${memoryId}:`, error);
      return null;
    }
  }

  async getMemoriesByType(type, limit = 20) {
    try {
      const index = await this.loadIndex();
      return index.memories
        .filter(memory => memory.type === type)
        .slice(0, limit);
    } catch (error) {
      console.error(`Error loading ${type} memories:`, error);
      return [];
    }
  }

  async loadIndex() {
    const content = await fs.readFile(this.indexPath, 'utf8');
    return JSON.parse(content);
  }

  async getStats() {
    try {
      const index = await this.loadIndex();
      const typeCount = {};
      index.memories.forEach(memory => {
        typeCount[memory.type] = (typeCount[memory.type] || 0) + 1;
      });

      return {
        totalMemories: index.totalCount,
        lastUpdated: index.lastUpdated,
        typeBreakdown: typeCount,
        oldestMemory: index.memories[index.memories.length - 1]?.date,
        newestMemory: index.memories[0]?.date
      };
    } catch (error) {
      return { error: 'No memories found' };
    }
  }
}

module.exports = ShaneBrainMemoryReader;
