```javascript
const express = require('express');
const fs = require('fs').promises;
const path = require('path');

const app = express();
app.use(express.json());

// In-memory store for user contexts (use Redis in production)
const userContexts = new Map();

app.post('/learn', async (req, res) => {
  try {
    const { userId, content, source, interaction } = req.body;

    // Get or create user context
    let context = userContexts.get(userId) || {
      personality: 'Shane-like responses: direct, helpful, entrepreneurial',
      memories: [],
      interactions: []
    };

    // Add new learning
    if (content) {
      context.memories.push({
        content,
        source,
        timestamp: new Date(),
        relevance: calculateRelevance(content)
      });
    }

    if (interaction) {
      context.interactions.push({
        ...interaction,
        timestamp: new Date()
      });
    }

    // Keep only recent/relevant items (last 100)
    context.memories = context.memories.slice(-100);
    context.interactions = context.interactions.slice(-50);

    userContexts.set(userId, context);

    // Persist to file
    await saveUserContext(userId, context);

    res.json({ success: true, contextSize: context.memories.length });
  } catch (error) {
    res.status(500).json({ error: 'Learning failed' });
  }
});

app.get('/context/:userId', async (req, res) => {
  try {
    const { userId } = req.params;
    let context = userContexts.get(userId);

    if (!context) {
      context = await loadUserContext(userId);
      userContexts.set(userId, context);
    }

    // Build context string for AI
    const contextString = `
PERSONALITY: ${context.personality}

RECENT MEMORIES:
${context.memories.slice(-5).map(m => `- ${m.content}`).join('\n')}

CONVERSATION STYLE:
${context.interactions.slice(-3).map(i => `User: ${i.message}\nShane: ${i.response}`).join('\n')}
    `.trim();

    res.json({ context: contextString });
  } catch (error) {
    res.status(500).json({ error: 'Context retrieval failed' });
  }
});

async function saveUserContext(userId, context) {
  const filepath = path.join(__dirname, 'contexts', `${userId}.json`);
  await fs.mkdir(path.dirname(filepath), { recursive: true });
  await fs.writeFile(filepath, JSON.stringify(context, null, 2));
}

async function loadUserContext(userId) {
  try {
    const filepath = path.join(__dirname, 'contexts', `${userId}.json`);
    const data = await fs.readFile(filepath, 'utf-8');
    return JSON.parse(data);
  } catch (error) {
    return {
      personality: 'Shane-like responses: direct, helpful, entrepreneurial',
      memories: [],
      interactions: []
    };
  }
}

function calculateRelevance(content) {
  // Simple relevance scoring
  const keywords = ['business', 'automation', 'AI', 'development', 'strategy'];
  return keywords.filter(word => content.toLowerCase().includes(word)).length;
}

app.listen(3003, () => {
  console.log('ShaneBrain Core running on port 3003');
});
